"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[615],{423:e=>{e.exports=JSON.parse('{"functions":[{"name":"Filter","desc":"Callback invoked for each raycast hit. Return `true` to allow the bullet\\nto bounce off the surface.\\n\\nMust be **synchronous** \u2014 yielding inside this callback will cause the cast\\nto be terminated with an error on the next frame.\\n\\nSignature: `(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean`\\n\\nDefault: `nil` (no bouncing)","params":[{"name":"callback","desc":"","lua_type":"(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":183,"path":"docs/SubBuilders.lua"}},{"name":"Max","desc":"Maximum total bounces across the bullet\'s entire lifetime.\\n\\nDefault: `5`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":193,"path":"docs/SubBuilders.lua"}},{"name":"SpeedThreshold","desc":"Minimum speed in studs per second required for a bounce attempt.\\nBelow this speed the hit is treated as a terminal impact.\\n\\nDefault: `20`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":204,"path":"docs/SubBuilders.lua"}},{"name":"Restitution","desc":"Energy-retention coefficient applied to reflected velocity. Must be in `[0, 1]`.\\n`1.0` = perfectly elastic (no energy loss). `0.0` = bullet stops on first contact.\\n\\nDefault: `0.7`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":215,"path":"docs/SubBuilders.lua"}},{"name":"MaterialRestitution","desc":"Per-material restitution multipliers, keyed by `Enum.Material`.\\nCombined multiplicatively with the base restitution in [BounceBuilder:Restitution].\\nOmitted materials use a multiplier of `1.0`.\\n\\n```lua\\n:MaterialRestitution({\\n    [Enum.Material.Concrete] = 0.5,\\n    [Enum.Material.Plastic]  = 0.95,\\n})\\n```\\n\\nDefault: `{}`","params":[{"name":"value","desc":"","lua_type":"{[Enum.Material]: number}"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":234,"path":"docs/SubBuilders.lua"}},{"name":"NormalPerturbation","desc":"Adds random noise to the surface normal before reflecting, simulating rough\\nor irregular surfaces. `0` = clean mirror reflection.\\n\\nDefault: `0.0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":245,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":252,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"BounceBuilder","desc":"Sub-builder for bounce configuration. Opened via [BehaviorBuilder:Bounce].\\nCall `:Done()` to return to the root [BehaviorBuilder].\\n\\n:::caution\\nPierce and bounce are mutually exclusive per hit. Bounce is only evaluated\\nif pierce did not occur.\\n:::","source":{"line":167,"path":"docs/SubBuilders.lua"}}')}}]);